void solve(int CASE)
{
	string s; cin >> s;
	ll n = s.size(); s = ' ' + s;
	int cnto = 0, cntw = 0;
	fa(i, 1, n)cnto += s[i] == 'o', cntw += s[i] == '?';
	ll ans = 0;
	fa(o, cnto, cnto + cntw) { // 枚举总共用多少 o
		var dp = Vec2<ll>(n + 1, o + 1, -1);
		dp[0][0] = 0;
		fa(i, 1, n)fa(j, 0, o)if (dp[i - 1][j] != -1) {
			if (s[i] == 'o') {
				if (j < o)dp[i][j + 1] = max(dp[i][j + 1], dp[i - 1][j]);
			}
			else if (s[i] == 'v') {
				dp[i][j] = max(dp[i][j], dp[i - 1][j] + (o * 1ll - j) * j);
			}
			else {
				if (j < o)dp[i][j + 1] = max(dp[i][j + 1], dp[i - 1][j]);
				dp[i][j] = max(dp[i][j], dp[i - 1][j] + (o * 1ll - j) * j);
			}
		}
		ans = max(ans, dp[n][o]);
	}
	cout << ans << endl;
	return;
}
